skin.stylesheet:
				 /*=============================================== *
 * Jcink.com Forum Hosting Stylesheet
 * ==============================================
 * #Version:	1.0.2
 *=============================================== */


html { overflow-x: auto; } 
form { display:inline; }

@import url('https://fonts.googleapis.com/css2?family=Cormorant+SC:wght@300;400;500;600;700&family=Cormorant:ital,wght@0,300;0,400;0,500;0,600;0,700;1,300;1,400;1,500;1,600;1,700&display=swap');

@import url('https://fonts.googleapis.com/css2?family=EB+Garamond:ital,wght@0,400;0,500;0,600;0,700;0,800;1,400;1,500;1,600;1,700;1,800&display=swap');

@import url('https://fonts.googleapis.com/css2?family=Lato:ital,wght@0,100;0,300;0,400;0,700;0,900;1,100;1,300;1,400;1,700;1,900&display=swap');
@import url('https://fonts.googleapis.com/css2?family=Cormorant+SC:wght@300;400;500;600;700&family=Cormorant:ital,wght@0,300;0,400;0,500;0,600;0,700;1,300;1,400;1,500;1,600;1,700&display=swap');

@import url('https://fonts.googleapis.com/css2?family=EB+Garamond:ital,wght@0,400;0,500;0,600;0,700;0,800;1,400;1,500;1,600;1,700;1,800&display=swap');

@import url('https://fonts.googleapis.com/css2?family=Lato:ital,wght@0,100;0,300;0,400;0,700;0,900;1,100;1,300;1,400;1,700;1,900&display=swap');


/****************************************
   SKIN UNIVERSALS
*****************************************/

:root {

   /* group colors */
   --amethyst1: 260 30% 20%;
   --amethyst2: 260 60% 60%;
   --diamond1: 194 10% 25%;
   --diamond2: 194 20% 60%;
   --jade1: 130 23% 20%;
   --jade2: 130 23% 50%;
   --onyx1: 240 8% 15%;
   --onyx2: 240 10% 50%;
   --pearl1: 300 20% 20%;
   --pearl2: 300 30% 55%;
   --ruby1: 0 40% 20%;
   --ruby2: 0 40% 40%;
   --sapphire1: 218 50% 20%;
   --sapphire2: 218 50% 50%;
   --corlucet1: 40 30% 20%;
   --corlucet2: 40 30% 55%;

   /* element colors */
   --ether: 54 48% 70%;
   --air: 36 60% 60%;
   --fire: 0 40% 50%;
   --earth: 140 40% 40%;
   --water: 218 60% 50%;
   --nether: 267 35% 50%;

   /* fonts */
   --norman: "norman-variable", serif;
   --norman-feature-settings: 'ss01' on, 'ss12' on;
   --stencil: "norman-stencil", serif;
   --fontserif: 'Cormorant', serif;
   --fontSC: 'Cormorant SC', serif;
   --fontsans: 'Lato', sans-serif;

   --sans8: 8px/1em var(--fontsans);
   --sans9: 9px/1em var(--fontsans);
   --sans10: 10px/1.5em var(--fontsans);
   --sans11: 11px/1.5em var(--fontsans);
   --sans12: 12px/1.5em var(--fontsans);
   --sans13: 13px/1.4em var(--fontsans);
   --sans14: 14px/1.5em var(--fontsans);
   --sans15: 15px/1.5em var(--fontsans);
   --sans16: 16px/1.55em var(--fontsans);
   --sans20: 20px/1.5em var(--fontsans);

   --serif14: 14px/1.2em var(--fontserif);
   --serif16: 16px/1.2em var(--fontserif);
   --serif17: 17px/1.2em var(--fontserif);
   --serif18: 18px/1.2em var(--fontserif);
   --serif20: 20px/1.2em var(--fontserif);
   --serif22: 22px/1.2em var(--fontserif);
   --serif24: 24px/1.2em var(--fontserif);
   --serif28: 28px/1.2em var(--fontserif);
   --serif30: 30px/1.2em var(--fontserif);
   --serif36: 30px/1.2em var(--fontserif);
   --serif40: 40px/1.2em var(--fontserif);
   --serif48: 48px/1.2em var(--fontserif);
   --serif60: 60px/1.2em var(--fontserif);
   --serif64: 64px/1.2em var(--fontserif);

   --norman20: 20px/1.5 var(--norman);
   --norman28: 28px/1.5 var(--norman);
   --norman30: 30px/1.2em var(--norman);
   --norman32: 32px/1.5em var(--norman);
   --norman36: 36px/1.5em var(--norman);
   --norman48: 48px/1.5em var(--norman);
   --norman56: 56px/1em var(--norman);

   /* tarot */
   --Chariot: url(/index.php?act=Attach&type=main&id=10);
   --Death: url(/index.php?act=Attach&type=main&id=11);
   --Fool: url(/index.php?act=Attach&type=main&id=12);
   --Hierophant: url(/index.php?act=Attach&type=main&id=13);
   --Justice: url(/index.php?act=Attach&type=main&id=14);
   --Lover: url(/index.php?act=Attach&type=main&id=15);
   --Moon: url(/index.php?act=Attach&type=main&id=16);
   --Star: url(/index.php?act=Attach&type=main&id=17);
   --Sun: url(/index.php?act=Attach&type=main&id=18);
   --Temperance: url(/index.php?act=Attach&type=main&id=19);
   --Tower: url(/index.php?act=Attach&type=main&id=20);

   /* blend modes */
   --lighten: lighten;

   /* inset padding */
   --insetgap: 8px;
}




:root.light-theme {

   /* group colors */
   --amethyst1: 260 40% 60%;
   --amethyst2: 260 40% 50%;
   --diamond1: 194 13% 50%;
   --diamond2: 194 30% 40%;
   --jade1: 130 30% 40%;
   --jade2: 130 30% 40%;
   --onyx1: 230 10% 50%;
   --onyx2: 230 10% 40%;
   --pearl1: 320 20% 65%;
   --pearl2: 320 30% 50%;
   --ruby1: 0 45% 50%;
   --ruby2: 0 40% 45%;
   --sapphire1: 218 50% 50%;
   --sapphire2: 218 50% 50%;
   --corlucet1: 50 40% 40%;
   --corlucet2: 50 50% 40%;

   /* element colors */
   --ether: 54 60% 40%;
   --air: 36 70% 50%;
   --fire: 0 60% 50%;
   --earth: 140 50% 40%;
   --water: 218 80% 40%;
   --nether: 267 40% 45%;

   /* blend modes */
   --lighten: darken;

}




/****************************************
   SKIN v2: INDIGO COLORS
*****************************************/

:root {
   /* low number dark, high number light */
   --htmlbg: 230 10% 13%;
   --main: 230 15% 15%;
   --accent1-med: 30 15% 55%;
   --accent1-light: 30 25% 70%;
   --accent2-med: 220 10% 45%;
   --accent2-light: 220 10% 40%;
   --darkgray: 230 15% 10%;
   --gray1: 220 10% 30%;
   --gray2: 220 1% 66%;
   --gray3: 0 0% 75%;
   --white: 0 0% 100%;
   --black: 0 0% 0%;
   --permblack: 0 0% 0%;
   --permwhite: 0 0% 75%;
   --bordercolor: hsl(var(--white) / .1);
   --grp1: var(--accent2-med);
   --grp2: var(--accent2-light);

   --onyx1: 240 10% 15%;
   --onyx2: 240 17% 50%;


   /* images */
   --texture-h: url(https://media.discordapp.net/attachments/1147949924374302721/1147950403946819737/texture-h.png?width=1330&height=886);
   --texture-v: url(https://media.discordapp.net/attachments/1147949924374302721/1147950404588552192/texture-v.png?width=590&height=884);

   --hero-bg: url(https://media.discordapp.net/attachments/1147949924374302721/1147957947784241172/d-hero-bg.png?ex=65f73326&is=65e4be26&hm=46c319a782dbbe50543046b655e263f33349014de90cef8c6dabf8a8f401a81b&=&format=webp&quality=lossless&width=1050&height=700);
   --hero: url(https://media.discordapp.net/attachments/1147949924374302721/1148038901261422602/hero.png?ex=65f77e8b&is=65e5098b&hm=022697197e81bbe8ffed5545d1b3d256d0c38634497872fb3eb98913dabf9946&=&format=webp&quality=lossless&width=1494&height=908);
   --gbfbg: url(https://media.discordapp.net/attachments/1147949924374302721/1158082889930526881/guidebookbg.png?ex=65f71ebd&is=65e4a9bd&hm=59ce4853d2e9e20b6144468a37a9d4e4589d6d023c944f2ac3ae4ad1fcdb4bc6&=&format=webp&quality=lossless&width=1674&height=908);
   --factionsbg: url(https://media.discordapp.net/attachments/1147949924374302721/1158082889599156276/factionsbg.png?ex=65f71ebd&is=65e4a9bd&hm=76e3217788a0502ed951f25f0cb1711e78675a0bc3e744f371a84b1b37a032cf&=&format=webp&quality=lossless&width=1738&height=908);
   --archivesbg: url(https://media.discordapp.net/attachments/1147949924374302721/1147967189656285195/archivesbg.png?ex=65f73bc2&is=65e4c6c2&hm=5a4ba0cb3a422d9680ae86cbbc5bc4685ec4bacb5c2045c238d1ca0085944436&=&format=webp&quality=lossless&width=1100&height=560)
}


:root.light-theme {
   /* low number dark, high number light */
   --htmlbg: 220 4% 73%;
   --main: 220 3% 75%;
   --accent1-med: 35 20% 40%;
   --accent1-light: 35 20% 40%;
   --accent2-med: 210 20% 30%;
   --accent2-light: 210 35% 35%;
   --darkgray: 180 2% 80%;
   --gray1: 190 10% 64%;
   --gray2: 180 1% 12%;
   --gray3: 0 0% 12%;
   --white: 0 0% 0%;
   --black: 0 0% 100%;
   --permwhite: 0 0% 100%;
   --bordercolor: hsl(var(--white) / .1);
   --grp1: var(--accent2-med);
   --grp2: var(--accent2-light);

   --hero-bg: var(--hero-bg-light);

}

/*
:root, :root.light-theme {
   --ruby1: 245 70% 40%;
   --ruby2: 245 75% 60%;
}
*/



/****************************************
   SKIN v1: TEAL COLORS
*****************************************/


[skin-version='v1'] {

   /* low number dark, high number light */
   --htmlbg: 210 10% 13%;
   --main: 200 12% 15%;
   --accent1-med: 32 16% 52%;
   --accent1-light: 36 20% 67%;
   --accent2-med: 180 25% 30%;
   --accent2-light: 180 25% 44%;
   --darkgray: 190 8% 9%;
   --gray1: 190 10% 30%;
   --gray2: 190 1% 66%;
   --gray3: 0 0% 75%;
   --white: 0 0% 100%;
   --black: 0 0% 0%;
   --permblack: 0 0% 0%;
   --permwhite: 0 0% 75%;
   --bordercolor: hsl(var(--white) / .1);
   --grp1: var(--accent2-med);
   --grp2: var(--accent2-light);


   /* images */
   --texture-h: url(https://media.discordapp.net/attachments/1147949924374302721/1147950403946819737/texture-h.png?width=1330&height=886);
   --texture-v: url(https://media.discordapp.net/attachments/1147949924374302721/1147950404588552192/texture-v.png?width=590&height=884);
   --hero-bg: url(https://media.discordapp.net/attachments/1147949924374302721/1147950218088808549/d-hero-bg.png?width=1330&height=886);
   --hero-bg-light: url(https://media.discordapp.net/attachments/1147949924374302721/1147950493012873358/l-hero-bg.png?width=1330&height=886);
   --hero: url(https://media.discordapp.net/attachments/1147949924374302721/1147950218722156715/hero.png?width=1454&height=886);
   --gbfbg: url(https://media.discordapp.net/attachments/1147949924374302721/1148273005647118376/guidebookbg.png?width=1634&height=886);
   --factionsbg: url(https://media.discordapp.net/attachments/1147949924374302721/1147950621215948912/factionsbg.png?width=1696&height=886);
   --archivesbg: url(https://media.discordapp.net/attachments/1147949924374302721/1147950620922359848/archivesbg.png?width=1742&height=886);

}


[skin-version='v1'].light-theme {
   /* low number dark, high number light */
   --htmlbg: 200 2% 74%;
   --main: 180 3% 75%;
   --accent1-med: 42 50% 30%;
   --accent1-light: 42 40% 31%;
   --accent2-med: 180 50% 30%;
   --accent2-light: 180 65% 30%;
   --darkgray: 180 2% 80%;
   --gray1: 190 10% 64%;
   --gray2: 180 1% 12%;
   --gray3: 0 0% 12%;
   --white: 0 0% 0%;
   --black: 0 0% 100%;
   --permwhite: 0 0% 100%;
   --bordercolor: hsl(var(--white) / .1);
   --grp1: var(--accent2-med);
   --grp2: var(--accent2-light);

   /* images */
   --hero-bg: var(--hero-bg-light);

}




/****************************************
   CUSTOM BOARD IMAGES
*****************************************/

.amethysttab-bg {
   background: url(https://media.discordapp.net/attachments/1027906385847009280/1095774463502585946/Amethyst.png?width=810&height=824);
}

.diamondtab-bg {
   background: url(https://media.discordapp.net/attachments/1027906385847009280/1092505423011135568/Diamond.png?width=932&height=948);
}

.jadetab-bg {
   background: url(https://media.discordapp.net/attachments/1027906385847009280/1092505423334101002/Jade.png?width=932&height=948);
}

.onyxtab-bg {
   background: url(https://media.discordapp.net/attachments/1027906385847009280/1092505423724163122/Onyx.png?width=932&height=948);
}

.pearltab-bg {
   background: url(https://media.discordapp.net/attachments/1027906385847009280/1095774463854919770/Pearl.png?width=810&height=824);
}

.rubytab-bg {
   background: url(https://media.discordapp.net/attachments/1027906385847009280/1092505424395260024/Ruby.png?width=932&height=948);
}

.sapphiretab-bg {
   background: url(https://media.discordapp.net/attachments/1076702682754064406/1096877244821024778/location-sapphire.png?width=810&height=824);
}

.corlucettab-bg {
   background: url(https://media.discordapp.net/attachments/1027906385847009280/1092505422667198574/Corlucet.png?width=932&height=948);
}

#for-35 .event-bg,
#for-35.event-forum::before { 
background-image: url(https://media.discordapp.net/attachments/1027906385847009280/1146096784691708044/920-rock-storm-ship-darkness-fantasy-art-4k.png?width=1574&height=886); 
background-size: 110%;
}

#for-35.event-forum::before {
grid-area: eventimg;
content: ' ';
position: absolute;
width: 100%;
height: 100%;
background-position: center;
opacity: .2;
}

@media only screen and (max-width: 800px) {
   #for-34 .event-bg {
      background-size: cover;
   }
}




/****************************************
   Global general table/div row styles
*****************************************/

.row1,
.row3,
.row4,
.row2 {
   padding: 2px 0 2px 10px!important;
   font: 400 var(--sans13);
   color: hsl(var(--gray2) / .7);
   border-bottom: 1px solid var(--bordercolor);
}

#post-preview .row1 {
   background: hsl(var(--main));
}

.activeuserstrip+.row2 {
   font: 400 var(--sans12);
}

.row2+.activeuserstrip {
   margin-top: 1em;
   border-top-width: 1px;
   gap: 4px;
}

#boardstats .row2 {
   text-align: center;
}

.darkrow1,
.darkrow2 {
   padding-left: 0 !important;
   text-align: left !important;
}

td.darkrow2 {
   display: none;
}

/* .darkrow3 {
   background-color: #D6D6D6;
   color: #000;
   padding: 3px;
}

.hlight {
   background-color: #EFEFEF;
}

.dlight {
   background-color: #EFEFEF;
} */

.wrapmini {
   display: none;
   float: left;
   margin-right: 24px;
   margin-bottom: 16px;
}

.wrapmini+div[align="right"] {
   clear: left;
}

.wrapmini img {
   height: 12px;
}

.wrapmini br {
   content: '';
   display: block;
   height: 4px;
}

#active-topics :where(.row1,.row2,.row3,.row4) {
    padding: 4px 0 !important;
    border-bottom: 1px solid var(--bordercolor);
}

.small a:not(:first-of-type) {
margin: 0 3px;
} 

/****************************************
   Top table bars / gradient holders 
*****************************************/

.maintitle {
   padding: 0;
}

.maintitle a:link,
.maintitle a:visited,
.maintitle a:active {
   text-decoration: none;
}

.maintitle a:hover {
   text-decoration: underline;
}


td.maintitle {
   display: table-cell;
   text-align: left;
   padding-left: 0 !important;
   padding-bottom: 0;
   text-transform: uppercase;
   color: hsl(var(--accent2-med));
   opacity: 0.7;
   border-bottom: 4px solid hsl(var(--accent2-light) / .2);
   font: var(--norman28);
   font-variation-settings: "wght" 540;
   font-feature-settings: 'ss01' off;
   letter-spacing: 0.05em;
}

.maintitle {
   text-transform: uppercase;
   color: hsl(var(--accent2-med));
   opacity: 0.7;
   border-bottom: 4px solid hsl(var(--accent2-light) / .2);
   font: var(--norman28);
   font-variation-settings: "wght" 540;
   font-feature-settings: 'ss01' off;
   letter-spacing: 0.05em;
}


/****************************************
   UserCP/My Controls styles
*****************************************/


#ucpmenu {
   width: 200px;
   padding-right: 16px;
   padding: 0 16px 0 0;
}

#ucpmenu p {
   margin: 0 0 12px;
   font-size: 0;
   color: hsl(var(--htmlbg));
}

#ucpmenu a {
   font: var(--sans13);
   letter-spacing: .05em;
   color: hsl(var(--accent2-light) / .7);
}


#ucpmenu a::before {
   content: '– ';
}

#ucpmenu+td {
   padding: 0 !important;
}

#ucpmenu .maintitle,
#ucpcontent .maintitle {
   display: block;
   text-align: left;
   margin: 0;
   padding-bottom: 1em;
   color: hsl(var(--accent2-med));
   opacity: 0.7;
   border-bottom: 0px solid hsl(var(--accent2-light) / .2);

   font: 600 var(--serif20);
   font-family: var(--fontSC);
   text-transform: lowercase;
   letter-spacing: .1em;
   color: hsl(var(--accent1-med));
   opacity: .8;

}

#ucpmenu .maintitle {
   padding: .5em 0 .5em;
   border-bottom: 1px solid hsl(var(--accent2-light) / .2);
}

#ucpmenu .pformstrip {
   padding-bottom: 4px;
}

#ucpcontent .maintitle {
   padding: .5em 0 .5em;
   border-bottom: 1px solid hsl(var(--acent2-light) / .2);
}

#ucpcontent>table:not(.maintitle),
#ucpcontent p {
   background: hsl(var(--main));
}

#ucpcontent .tableborder {
   background: hsl(var(--main));
}

#ucpcontent {
   font: 400 var(--sans13);
}

#ucpcontent>form {
   display: block;
   background: hsl(var(--main));
}

#ucpcontent p {
   padding: 10px 16px;
   margin: 0px;
   font: var(--sans14);
   color: hsl(var(--gray2) / 0.7);
}

#ucpcontent div.pformstrip {
   padding-left: 16px;
   padding-right: 16px;
   background: hsl(var(--main));
   border-bottom: 1px solid var(--bordercolor);
   background: hsl(var(--darkgray) / .5);
}

#ucpcontent td.pformstrip {
   padding-left: 16px;
   padding-right: 16px;
   background: hsl(var(--main));
   /* background: hsl(var(--darkgray) / .5); */
}

#ucpcontent .row1 {
   padding: 4px 16px !important;
}

#ucpcontent .row2 {
   background: hsl(var(--main));
}

#ucpcontent .row3 {
   background: hsl(var(--main));
}

#ucpcontent .row4 {
   background: hsl(var(--main));
   padding: 4px 16px !important;
   text-align: left;
}

.pformstrip input[type="submit"],
.pformstrip input[type="button"],
.pformstrip input[type="reset"] {
   margin-bottom: 0;
}

.ucpdivider {
    background: hsl(var(--htmlbg));
    color: hsl(var(--accent1-med));
    border-bottom: 1px solid hsl(var(--darkgray));
}

.ucpdivider h2,
.ucpdivider h3 b {
    margin: 1em 0;
    font: 700 var(--sans12);
    letter-spacing: 2px;
    text-transform: uppercase;
}

.ucpdivider h3 {
    margin: 1em 0;
    font: 700 var(--sans12);
}

/****************************************
  Bar directly below the maintitles 
*****************************************/

.titlemedium {
   font: 700 var(--sans12);
  /* text-transform: uppercase;
   letter-spacing: .1em; */
   color: hsl(var(--gray2) / .75);
   padding: 0 8px;
   background: hsl(var(--darkgray) / .5);
}

.titlemedium:not(:last-child) {
   border-right: 1px solid var(--bordercolor);
}

.titlemedium a:link,
.titlemedium a:visited,
.titlemedium a:active {
   text-decoration: none;
}

/****************************************
  Table & Div Borders 
*****************************************/


.tableborder {
   padding: 0px;
   margin: 0;
}

#ucpcontent .tableborder+br+.tableborder {
   border-top: 1px solid var(--bordercolor);
}

.tableborder+br+.tableborder {
   margin-top: 32px
}

.tablefill {
   background-color: hsl(var(--main));
   border: 1px solid var(--bordercolor);
   padding: 6px;
}

.tablepad {
   background-color: hsl(var(--main));
   padding: 6px;
}

.tablebasic {
   background-color: hsl(var(--main));
   width: 100%;
   padding: 0;
   margin: 0px;
   border: 0px;
}

.plainborder {
   border: 1px solid #555;
   background-color: #EFEFEF;
}

table {
   border-collapse: collapse;
}

.tablebasic .row1 {
   padding: 12px 0 !important;
   border-bottom: 1px solid var(--bordercolor);
}

/****************************************
  QUOTE and CODE BBCode boxes
*****************************************/

#QUOTE-WRAP {
   width: 100%;
   margin: 1em auto;
}

#QUOTE-WRAP tr:first-child {
   font: var(--sans12);
   letter-spacing: 0.1em;
   text-transform: uppercase;
}

#QUOTE {
   white-space: normal;
   padding: 1.25em;
   margin: 0;
   background: hsl(var(--gray1) / .3);
   border: 1px solid hsl(var(--darkgray));
   font: 400 var(--sans13);
   text-transform: none;
   letter-spacing: .05em;
   color: hsl(var(--gray2));
}

#CODE-WRAP {
   margin: 1em auto;
   max-width: 450px;
}

.code-top {
   background: linear-gradient(to right, hsl(var(--darkgray)/.95), hsl(var(--darkgray)/.95)), var(--texture-h) right / cover no-repeat;
   height: 50px;
   display: flex;
   align-items: center;
   justify-content: space-between;
   padding: 0 16px;
   border: 1px solid var(--bordercolor);
   border-bottom: 0;
}

.code-title {
   font: 700 12px/1.5em var(--fontsans);
   letter-spacing: 0.1em;
   text-transform: uppercase;
   color: hsl(var(--gray2));
}

.code-highlight {
   color: hsl(var(--accent2-light));
   font: 400 var(--sans9);
   letter-spacing: 0.2em;
   text-transform: uppercase;
   border: 1px solid hsl(var(--accent2-med) / .2);
   padding: 6px 8px;
   cursor: pointer;
}

#CODE {
   white-space: normal;
   padding: 16px;
   background: hsl(var(--gray1) / .3);
   border: 1px solid hsl(var(--darkgray));
   font: 400 var(--sans13);
   text-transform: none;
   letter-spacing: .05em;
   color: hsl(var(--gray2));
}

.code-scroll {
   max-height: 120px;
   overflow: auto;
}

/**********************************************
  Input buttons, e.g. submit, text input, etc
***********************************************/

.button-large {
   display: inline-flex;
   align-items: center;
   width: fit-content;
   height: 32px;
   padding: 0 10px;
   margin-left: 4px;
   background: hsl(var(--accent2-light) / .25);
   border: 1px solid var(--bordercolor);
   font: 700 var(--sans10);
   letter-spacing: 0.1em;
   text-transform: uppercase;
   color: hsl(var(--gray2));
   transition: .25s;
}

.button-large:hover {
   background: hsl(var(--accent2-med) / .2);
}

.button-large.closed {
   background: hsl(var(--accent2-med) / .2);
   padding: 7px 12px;
   text-align: center;
   margin: 0px 5px 0px 5px;
   font-weight: bold;
}

.button-small {
   background: hsl(var(--accent2-light) / .25);
   border: 1px solid var(--bordercolor);
   padding: 2px 4px;
   font: 700 var(--sans10);
   letter-spacing: 0.1em;
   text-transform: uppercase;
   color: hsl(var(--gray2));
   transition: .25s;
   min-width: 50px;
   max-width: 80px;
}

.post-buttons-top {
   margin-top: 3px;
}

input {
   background: hsl(var(--darkgray));
}

.forminput,
.codebuttons,
.textinput {
   border-radius: 0;
   /* -webkit-appearance: none;
   -moz-appearance: none;
   appearance: none; */

   vertical-align: middle;
   min-height: 32px;
   padding: 0 .75em;
   margin: 0 0 0 2px;
   background: hsl(var(--darkgray) / .85);
   border: 1px solid var(--bordercolor);
   font: 400 var(--sans13);
   text-transform: none;
   letter-spacing: .05em;
   color: hsl(var(--gray2));
}

.radiobutton,
.checkbox {
   background: hsl(var(--darkgray) / .85);
   border: 1px solid hsl(var(--darkgray));
}

.forminput::placeholder {
   opacity: .75;
}

.member-wrapper .forminput {
   width: 100%;
   height: 38px;
   margin: 0;
   border-color: hsl(var(--htmlbg));
}

.topic-rows-footer [type="submit"].forminput {
   padding: .25em 8px;
   border-color: var(--bordercolor);
}

input[type=submit],
input[type=button],
input[type=reset] {
   vertical-align: middle;
   display: inline-flex;
   align-items: center;
   justify-content: center;
   height: 32px;
   padding: 0 8px;
   margin: 0 0 0 2px;
   background: hsl(var(--accent2-light) / .25);
   border: 1px solid var(--bordercolor);
   font: 700 var(--sans10);
   letter-spacing: 0.1em;
   text-transform: uppercase;
   color: hsl(var(--gray2) / 1);
   transition: .25s;
}

input[type=submit]:hover,
input[type=button]:hover,
input[type=reset]:hover {
   background: hsl(var(--accent2-med) / .2);
}

#subaccounts_menu select[class*=foruminput] {
   background-color: var(--bordercolor);
   color: var(--white);
   font-size: 0.7rem;
   padding: 0.2rem;
}

#subaccounts_menu select option {
   padding: 2px 0;
   background-color: hsl(var(--darkgray));
}

.codebuttons {
   font-size: 10px;
}

.titlemedium input,
.titlemedium .forminput {
   min-height: unset;
   height: 24px;
   padding: 0 6px;
   border-color: hsl(var(--accent2-med) / .2);
}




/****************************************
  Form table cell styles, left/right/top
*****************************************/

.pformstrip {
   font: 700 var(--sans11);
   text-transform: uppercase;
   letter-spacing: .1em;
   color: hsl(var(--gray2) / .75);
   padding: 12px 0;
}


.pformleftw {
   background-color: hsl(var(--main));
   padding: 6px;
   margin-top: 1px;
   width: 40%;
   border-top: 1px solid #232323;
   border-right: 1px solid #232323;
}

.pformleft,
.pformright {
   border-bottom: 1px solid hsl(var(--darkgray));
   vertical-align: top;
   font: var(--sans12);
   color: hsl(var(--gray2) / .75);
}

.pformleft {
   width: 25%;
   padding: 12px 0 16px;
}

.pformright {
   padding: 10px 0;
   vertical-align: top;
}

.pformleft label {
   font: 700 var(--sans11);
   text-transform: uppercase;
   letter-spacing: .1em;
   color: hsl(var(--gray2));
}

#ucpcontent td.pformright textarea {
   max-width: 500px;
}

#ucpcontent table td {
   padding-left: 16px;
   padding-right: 16px;
}





/****************************************
  Posting Form
*****************************************/

#topic-settings-header .pformstrip,
#enter-your-post-header .pformstrip,
#code-buttons-header .pformstrip,
#post-as-header .pformstrip,
#post-as .pformstrip {
   padding-bottom: 2px;
}


#posting-form td {
   padding-left: 16px;
   padding-right: 16px;
}

#posting-form tr:not(:first-child) {
   background: hsl(var(--main));
}

#bbcode-buttons {
   display: block;
   margin-bottom: 0px;
}

#bbcode-buttons+br {
   display: none;
}

#post-icon-options { display: none; }

#bbcode-buttons input,
#bbcode-buttons select,
form[name="REPLIER"] input[name="button"] {
   min-height: unset;
   height: 24px;
   padding: 0 6px;
   border-color: hsl(var(--accent2-med) / .2);
   margin-bottom: 6px;
   margin-right: 4px;
}

#bbcode-buttons select {
   background: hsl(var(--accent2-light) / .25);
}


input[name="tagcount"],
input[name="helpbox"] {
   padding: .5em .75em !important;
}

td.right a {
   display: inline-block;
}

#smilies-table {
   display: none;
}

#editpost_custombuttons {
   text-align: left;
}

#enter-your-post .desc {
   text-align: left;
}

#topic_open + br + .bar > div:first-child {
   z-index: 5;
}

input[type=button].formatbuttons {
min-height: unset;
    height: 24px;
    padding: 0 6px;
    border-color: hsl(var(--accent2-med) / .2);

}

@media only screen and (max-width: 800px) {
   :is(#UserCP, #Msg) table,
   :is(#UserCP, #Msg) :where(thead, tbody, tr),
   #posting-form,
   #posting-form :where(thead, tbody, tr),
   #store table,
   #store :where(thead, tbody, tr),
   .threadfunctions,
   .threadfunctions :where(td) {
      display: block;
   }

   #ucpmenu {
      width: 100%;
      margin-bottom: 32px;
      padding: 0 40px 16px 0;
      display: grid;
      grid-auto-flow: column;
      gap: 0 32px;
      overflow: auto;
      grid-template-rows: auto auto;
      grid-auto-columns: 200px;
   }

   #ucpmenu .maintitle {
      display: none;
   }

   #ucpcontent {
      max-width: calc(100vw - 24px);
   }

   #ucpcontent table td,
   #posting-form td {
      display: block;
   }

   #store #ucpcontent td {
      display: table-cell;
   }

   .pformleft {
      width: 100%;
      border-bottom: 0;
      padding-bottom: 0;
   }

   #ucpcontent input[type="text" i],
   #ucpcontent textarea,
   #posting-form input[type="text" i],
   #posting-form textarea, 
   #qr_open textarea {
      width: 100%;
   }

   .store-menu>.row4 {
      display: none;
   }

   .threadfunctions td {
      width: calc(100vw - 24px) !important;
   }

   .threadfunctions td:first-of-type {
      margin-bottom: 20px;
   }

   /* Registration page styling for mobile */
   #Reg .tablepad {
      padding: 0;
   }

   #Reg tbody tr {
      display: flex;
      flex-flow: column nowrap;
      width: 100%;
      line-height: 150%;
   }

   #Reg fieldset table tr {
      flex-flow: row nowrap;
   }

   #Reg fieldset table tr td {
      display: flex;
   }

   #Reg fieldset table tr td input {
      width: 100%;
   }

   #Reg td,
   #Reg select {
      width: 100% !important;
   }

   #Reg fieldset {
      box-sizing: border-box;
      border: 0px;
      border-bottom: 1px solid;
   }

   #Reg td[width='12'] {
      display: none;
   }
}




/****************************************
  PAGINATION
*****************************************/


.newstext {
   display: none;
}

.pagination-wrap {
   border-spacing: 0 !important;
   margin-bottom: 36px;
}

.pagination {
   margin-left: -2px;
   font: 700 var(--sans12);
   letter-spacing: 0.1em;
   text-transform: uppercase;
   color: hsl(var(--gray2));
}

.pagination_pagetxt {
   display: none;
}

.pagination_current,
.pagination_page,
.pagination_last {
   display: inline-flex;
   align-items: center;
   height: 32px;
   padding: 0 10px;
   background: hsl(var(--accent2-light) / .1);
   border: 1px solid var(--bordercolor);
   color: hsl(var(--gray2));
   transition: .25s;
}

.pagination_last {
   font-size: 10px;
}

.pagination_page,
.pagination_last {
   background: hsl(var(--accent2-light) / 0);
}

.pagination_page:hover,
.pagination_last:hover {
   background: hsl(var(--main) / 1);
}



/****************************************
  Search
*****************************************/

form[name="sForm"] .pformstrip,
form[name="dateline"] .pformstrip {
   padding-top: 20px;
}

form[name="sForm"] .forminput#keywords {
   margin-bottom: .75em;
}

form[name="sForm"] .row1 br+br {
   content: '';
   display: none;
}

form[name="sForm"] .forminput,
form[name="dateline"] .forminput {
   padding: var(--insetgap);
   border-color: var(--bordercolor);
}

fieldset.search {
   border-color: var(--bordercolor);
}

label {
   display: inline-block;
   margin: 2px 0;
}



/***********************************
 Copyright: Removal is against Terms
************************************/

#delcookiesrow {
   text-align: right;
   margin-top: -.5em;
}

#delcookiesrow a {
   color: hsl(var(--gray1))
}

.copyrightwrap {
   background: hsl(var(--darkgray));
   border-top: 1px solid var(--bordercolor);
   padding: 2em 20px 6em;
}

.skincred {
   text-align: center;
   margin-bottom: -.5em;
   font: 800 var(--serif16);
   font-family: var(--fontSC);
   letter-spacing: .2em;
   text-transform: lowercase;
}

.copyright {
   font: var(--sans10)
}




.QA,
.qa,
.g-4,
a.mgroup-4,
.NPC,
.npc,
.g-14,
a.mgroup-16  {
   --grp1: var(--main, var(--accent2-med));
   --grp2: var(--accent1-light, var(--accent2-light));
}

.Unsorted,
.unsorted,
.g-3,
a.mgroup-3,
.default {
   --grp1: var(--unsorted1, var(--accent2-med));
   --grp2: var(--unsorted2, var(--accent2-light));
}


.Amethyst,
.amethyst,
.g-6,
a.mgroup-6 {
   --grp1: var(--amethyst1, var(--accent2-med));
   --grp2: var(--amethyst2, var(--accent2-light));
}

.Diamond,
.diamond,
.g-7,
a.mgroup-7 {
   --grp1: var(--diamond1, var(--accent2-med));
   --grp2: var(--diamond2, var(--accent2-light));
}

.Jade,
.jade,
.g-8,
a.mgroup-8 {
   --grp1: var(--jade1, var(--accent2-med));
   --grp2: var(--jade2, var(--accent2-light));
}

.Onyx,
.onyx,
.g-9,
a.mgroup-9 {
   --grp1: var(--onyx1, var(--accent2-med));
   --grp2: var(--onyx2, var(--accent2-light));
}

.Pearl,
.pearl,
.g-10,
a.mgroup-10 {
   --grp1: var(--pearl1, var(--accent2-med));
   --grp2: var(--pearl2, var(--accent2-light));
}

.Ruby,
.ruby,
.g-11,
a.mgroup-11 {
   --grp1: var(--ruby1, var(--accent2-med));
   --grp2: var(--ruby2, var(--accent2-light));
}

.Sapphire,
.sapphire,
.g-12,
a.mgroup-12 {
   --grp1: var(--sapphire1, var(--accent2-med));
   --grp2: var(--sapphire2, var(--accent2-light));
}

.Corlucet,
.corlucet,
.g-13,
a.mgroup-13 {
   --grp1: var(--corlucet1, var(--accent2-med));
   --grp2: var(--corlucet2, var(--accent2-light));
}

span:where(.QA,.amethyst,.diamond,.jade,.onyx,.pearl,.ruby,.sapphire,.corlucet) {
   color: hsl(var(--grp2));
}


html {
   background: hsl(var(--htmlbg));
   scroll-behavior: smooth;
}

html * {
   box-sizing: border-box;
   position: relative;
}

body {
   background: hsl(var(--htmlbg));
   margin: 0;
   font-size: 13px;
   font-family: var(--fontsans);
   color: hsl(var(--gray2));
}

a {
   display: inline-block;
   text-decoration: none;
   color: hsl(var(--grp2, var(--accent2-light)));
   transition: .25s;
   cursor: pointer;
}

#appwrap a {
   color: hsl(var(--grp2))
}

a:hover {
   opacity: .85;
   transition: .25s;
}

body::before {
   position: fixed;
   content: '';
   top: 0;
   width: 100%;
   height: 100%;
   background: var(--texture-h) center / cover;
   opacity: .1;
   mix-blend-mode: overlay;
}

.masterwrapper {
   width: 1200px;
   margin: auto auto;
   background: hsl(var(--darkgray) / .7);
}

.perms-admin,
.perms-logged,
.perms-guest {
   display: none !important;
}


/* guest nav links */
.perms_g-1 .perms-guest,
.perms_g-2 .perms-guest {
   display: block !important;
}

.perms_g-1 .bp-userbox .perms-guest, 
.perms_g-2 .bp-userbox .perms-guest {
   display: inline-block !important;
}

:where(.perms_g-3, .perms_g-4 .perms_g-6, .perms_g-7, .perms_g-8, .perms_g-9, .perms_g-10, .perms_g-11, .perms_g-12, .perms_g-13, .perms_g-14) .perms-guest {
   display: none;
}

/* staff group nav links */
.perms_g-4 .perms-admin,
.perms_g-14 .perms-admin {
   display: block !important;
}

/* member group nav links */
:where(.perms_g-3, .perms_g-4, .perms_g-6, .perms_g-7, .perms_g-8, .perms_g-9, .perms_g-10, .perms_g-11, .perms_g-12, .perms_g-13, .perms_g-14) .perms-logged {
   display: block !important;
}

:where(.perms_g-3, .perms_g-4, .perms_g-6, .perms_g-7, .perms_g-8, .perms_g-9, .perms_g-10, .perms_g-11, .perms_g-12, .perms_g-13, .perms_g-14) .topnav-userbox .perms-logged {
   display: flex !important;
}

:where(.perms_g-3, .perms_g-4, .perms_g-6, .perms_g-7, .perms_g-8, .perms_g-9, .perms_g-10, .perms_g-11, .perms_g-12, .perms_g-13, .perms_g-14)  .bp-userbox .perms-logged {
   display: inline-block !important;
}

button.colortoggle {
   all: unset;
   display: block;
   cursor: pointer;
}


.ph-moon {
   display: none;
}

.light-theme .ph-sun {
   display: none;
}

.light-theme .ph-moon,
.dark-theme .ph-sun {
   display: block;
}

.topnav {
   position: sticky;
   z-index: 100;
   top: 0;
   display: grid;
   grid-template: 'toggled mainlinks quicklinks userbox' 50px / 0 auto auto 0;
   align-items: center;
   width: 100%;
   height: 50px;
   padding: 0 56px 0 28px;
   background: hsl(var(--darkgray) / .4);
   backdrop-filter: blur(7.5px);
   -webkit-backdrop-filter: blur(7.5px);
   border-bottom: 1px solid var(--bordercolor);
   transition: .4s;
}


.topnav a,
.topnav .colortoggle {
   font: var(--sans10);
   letter-spacing: .2em;
   text-transform: uppercase;
   color: hsl(var(--gray3));
}

.topnav>div {
   transition: opacity .2s .2s;
}

.topnav-toggled {
   grid-area: toggled;
   display: flex;
   align-items: center;
}

.topnav-main {
   grid-area: mainlinks;
}

.topnav-quicklinks {
   grid-area: quicklinks;
   justify-content: flex-end;
}

.topnav-userbox {
   grid-area: userbox;
}

.topnav-main,
.topnav-quicklinks {
   display: inline-flex;
   align-items: center;
   gap: 16px 20px;
}

.topnav-main a,
.topnav-quicklinks a,
.topnav .colortoggle {
   color: hsl(var(--gray3));
   transition: .25s;
}

.responsive.topnav {
   grid-template: 'mainlinks quicklinks toggled userbox' 50px / 1fr auto auto 0;
}

.responsive .topnav-main,
.topnav-quicklinks,
.topnav-userbox,
.topnav-toggled {
   width: 0;
   opacity: 0;
   overflow: hidden;
}


.responsive .topnav-quicklinks,
.responsive .topnav-toggled {
   opacity: 1;
   width: auto;
}

.topnav-quicklinks a,
.topnav-userbox a,
.topnav .colortoggle {
   color: hsl(var(--accent2-light));
}

.topnav-currentacc {
   margin-bottom: 1em;
   font: var(--sans9);
   letter-spacing: 0.2em;
   text-transform: uppercase;
}

.mobilenav-avatar {
   display: block;
   border: 1px solid var(--bordercolor);
   padding: 3px;
   width: 40px;
   height: 40px;
   border-radius: 100%;
   margin-left: 20px;
}

.mobilenav-avatar img {
   display: block;
   width: 100%;
   height: 100%;
   object-fit: cover;
   border-radius: 100%;
}

.mobilenav {
   position: absolute;
   top: 0;
   right: 0;
   width: 50px;
   height: 50px;
   display: flex;
   align-items: center;
   justify-content: center;
   font-size: 18px !important;
   color: hsl(var(--gray3));
   transition: none;
}

.mobilenav:hover,
.mobilehome:hover {
   color: hsl(var(--accent1-light))
}

.ph-list,
.ph-x {
   position: absolute;
   transition: .25s;
}

.ph-x,
.responsive .ph-list {
   opacity: 0;
}

.ph-list,
.responsive .ph-x {
   opacity: 1;
}

.mobilehome {
   width: 50px;
   height: 50px;
   display: flex;
   align-items: center;
   justify-content: center;
   font-size: 18px;
   color: hsl(var(--gray3));
   transition: none;
   display: none;
   opacity: 0;
}

.mobilehome .ph {
   font-size: 18px;
}

#clicktodismiss {
   position: absolute;
   top: 0;
   height: 100%;
   width: 100%;
   z-index: 70;
}

@media only screen and (max-width: 800px) {
   .topnav {
      padding: 0 20px 0 20px;
      height: 50px;
      display: grid;
      grid-template:
         '.' 50px
         'mainlinks'
         'quicklinks'
         'userbox' / 1fr;
      grid-auto-flow: row;
      align-items: flex-start;
      justify-content: flex-start;
      align-content: flex-start;
      overflow: hidden;
   }

   .responsive.topnav {
      grid-template:
         '.' 50px
         'mainlinks' 195px
         'quicklinks' 221px
         'userbox' 200px / 1fr;
      height: 100vh;
      overflow: auto;
      flex-direction: column;
      background: hsl(var(--darkgray) / .9);
      opacity: 1;
   }

   .topnav-toggled,
   .responsive .topnav-toggled {
      position: absolute;
      left: 0;
      width: calc(50% + 20px);
      height: 50px;
      opacity: 1;
      justify-content: space-between;
   }

   .mobilehome {
      display: flex;
      opacity: 1;
   }

   .topnav-main,
   .topnav-quicklinks,
   .topnav-userbox {
      display: block;
      width: 100%;
      opacity: 0;
      align-items: center;
      justify-content: unset;
   }

   .responsive .topnav-main,
   .responsive .topnav-quicklinks,
   .responsive .topnav-userbox {
      width: 100%;
      opacity: 1;
   }

   .topnav-main a,
   .topnav-quicklinks a,
   .topnav-userbox a,
   .topnav .colortoggle {
      display: flex;
      margin-bottom: 1em;
   }

   .topnav-main,
   .topnav-userbox {
      margin: 1em 0;
   }

   .topnav-quicklinks,
   .topnav-userbox {
      border-top: 1px solid hsl(var(--white) / .2);
      padding-top: 24px;
   }

   .topnav-main a:hover,
   .topnav-quicklinks a:hover,
   .topnav-userbox a:hover,
   .topnav .colortoggle:hover {
      margin-left: 1em;
   }

   .topnav-userbox .ph {
      margin-right: 4px;
      font-size: 16px;
   }
}






.banner {
   background: var(--hero-bg);
   height: 730px;
   margin-top: -50px;
   -webkit-mask-image: linear-gradient(180deg, #000000 60%, #00000000 100%);
   mask-image: linear-gradient(180deg, #000000 60%, #00000000 100%);
}

.hero {
   background: var(--hero) center / cover no-repeat;
   height: 100%;
   width: 100%;
   -webkit-mask-image: linear-gradient(180deg, #000000 60%, #00000000 100%);
   mask-image: linear-gradient(180deg, #000000 60%, #00000000 100%);
}

/* for skin 2 blue */
.hero {
   background-position: center right 50px;
}

.sidenav {
   position: absolute;
   z-index: 50;
   top: 50px;
   right: 0;
   width: 50px;
   height: calc(100% - 50px);
   padding: 0 0 16px;
   background: hsl(var(--darkgray) / .7);
   border-left: 1px solid var(--bordercolor);
   font-size: 16px
}

.sidenav div {
   display: flex;
   flex-direction: column;
   align-items: center;
   justify-content: end;
   gap: 10px;
   position: sticky;
   top: calc(100% - 90px);
}

.sidenav a {
   color: hsl(var(--gray3));
}

.hero-text {
   position: absolute;
   top: 260px;
   left: 50px;
   z-index: 20;
}

.hero-text h1 {
   all: unset;
   display: block;
   margin-top: 44px;
   font: 800 80px/1em var(--stencil);
   letter-spacing: 0.15em;
   color: hsl(var(--accent1-light));
   overflow: .9;
}

.hero-text div:last-child {
   margin-top: -12px;
   font: 500 var(--serif20);
   font-family: var(--fontSC);
   text-transform: lowercase;
   letter-spacing: .15em;
   color: hsl(var(--accent1-light));
   opacity: .8;
   mix-blend-mode: exclusion;
}

.bannerpanel {
   position: absolute;
   width: 280px;
   height: 512px;
   top: 125px;
   right: 100px;
   display: grid;
   grid-template:
      'bpheader' 130px
      'bpbody' 1fr;
   overflow: auto;
}

.bp-navwrap {
   position: relative;
   display: flex;
   align-items: center;
   justify-content: center;
   position: absolute;
   height: 512px;
   width: 50px;
   top: 125px;
   right: 50px;
   writing-mode: vertical-rl;
   text-orientation: mixed;
}

.bp-navwrap>div {
   gap: 18px;
}

.bp-nav-label {
   display: flex;
   gap: 12px;
   font: 400 var(--sans8);
   letter-spacing: .25em;
   text-transform: uppercase;
   color: hsl(var(--gray3));
   cursor: pointer;
   transition: opacity .25s;
}

.marker {
   display: inline-block;
   width: 6px;
   height: 6px;
   margin-right: 1px;
   border: 1px solid hsl(var(--white));
   transform: rotate(45deg);
   opacity: .5;
   transition: .5s;
}

.markerhighlight {
   position: absolute;
   top: 63.5px;
   left: -2px;
   width: 12px;
   height: 12px;
   border: 1px solid hsl(var(--white));
   filter: drop-shadow(0px 4px 4px #000000);
   transform: rotate(45deg);
   transition: .5s;
}

.markerhighlight.news {
   top: 87.5px;
}

.bp-nav-label.active {
   font-weight: 800;
   opacity: 1;
}

.marker.active {
   background: hsl(var(--white));
   opacity: 1;
}

.bp-header {
   grid-area: bpheader;
   background: hsl(var(--darkgray) / .7);
   backdrop-filter: blur(12.5px);
   -webkit-backdrop-filter: blur(12.5px);
   border: 1px solid hsl(var(--gray1) / .3);
   border-bottom-color: hsl(var(--darkgray));
   display: flex;
   align-items: center;
   justify-content: space-between;
   padding: 0 24px;
}

.bp-body {
   grid-area: bpbody;
   background: hsl(var(--gray1) / .4);
   backdrop-filter: blur(12.5px);
   -webkit-backdrop-filter: blur(12.5px);
   overflow: hidden;
}

[class*=bp-slide] {
   height: 100%;
   display: flex;
   flex-direction: column;
   justify-content: space-between;
   transition: .5s;
}

.bp-infobox,
.bp-linksbox,
.bp-newsbox,
.bp-eventbox {
   font: var(--sans13);
   padding: 20px;
}

.bp-infobox,
.bp-newsbox {
   border-bottom: 1px solid hsl(var(--gray1) / .5);
   flex-grow: 2;
}

.bp-newsbox {
   max-height: 222px;
   overflow: auto;
}

.bp-newsbox b {
   color: hsl(var(--accent1-med));
}

.bp-linksbox {
   column-count: 2;
}

.bp-linksbox a {
   display: block;
   width: fit-content;
   margin-bottom: 8px;
   font: 700 var(--sans10);
   letter-spacing: .2em;
   text-transform: uppercase;
   color: hsl(var(--accent2-light));
}

.bp-linksbox a:hover {
   margin-left: 4px;
}

.bp-linksbox a:nth-child(4),
.bp-linksbox a:last-child {
   margin-bottom: 0;
}

.bp-body.welcome .bp-slide:first-child {
   margin-top: 0;
}

.bp-body.news .bp-slide:first-child {
   margin-top: -382px;
}

.bp-username {
   margin-bottom: 2px;
   display: flex;
   gap: 4px;
   font: 700 var(--serif17);
   font-family: var(--fontSC);
   text-transform: lowercase;
   letter-spacing: .1em !important;
   color: hsl(var(--accent2-med));
}

.bp-userlink {
   display: inline-flex;
   padding: 8px;
   margin-top: 2px;
   background: hsl(var(--gray1) / 0.1);
   border: 1px solid hsl(var(--black) / 0.25);
   font: 700 var(--sans8);
   letter-spacing: .2em;
   text-transform: uppercase;
   color: hsl(var(--gray2));
}

.bp-accswitch {
   margin-top: 3px;
   font-size: 16px;
   cursor: pointer;
}

.bp-accswitch .ph {
   padding: 2px;
}

.bp-accswitch-dropdown {
   position: absolute;
   padding: 8px 0;
   top: 21px;
   background: hsl(var(--darkgray));
   width: fit-content;
   box-shadow: inset 0 0 40px 40px hsl(var(--darkgray) / 1);
   transition: top .3s, opacity .3s;
   display: none;
   z-index: 5;
}

.bp-accswitch-dropdown.is_active {
   display: block;
}

.bp-username #subaccounts_menu form {
   display: inline-block;
}

.bp-username #subaccounts_menu .forminput {
   display: block;
   width: min-content;
   max-width: 160px;
   height: 24px;
   min-height: unset;
   padding: .25em .5em;
   background: hsl(var(--main) / .3);
   border-color: var(--bordercolor);
   font: 700 10px/1.5em var(--fontsans);
   letter-spacing: .15em;
   text-transform: uppercase;
   color: hsl(var(--gray2) / .75);
}

.bp-avatar {
   border: 1px solid hsl(var(--gray1) / .5);
   padding: 4px;
   width: 60px;
   height: 60px;
   min-width: 60px;
}

.bp-avatar img {
   display: block;
   width: 100%;
   height: 100%;
   object-fit: cover;
object-position: top;
}

.bp-eventbox {
max-height: 160px;
}

.eventcard {
   width: 100%;
   height: min(100%, 120px);
   background: hsl(var(--darkgray));
}

.eventcard img {
   width: 100%;
   height: calc(100% - 28px);
   object-fit: cover;
   object-position: center;
}

.eventcard-label {
   font: 700 var(--sans8);
   letter-spacing: .25em;
   text-transform: uppercase;
   color: hsl(var(--accent2-light));
   padding: 6px 12px 8px;
}

.wrapper {
   padding: 0 100px 64px 50px;
   margin-top: -32px;
}

#navstrip {
   border-top: 1px solid var(--bordercolor);
   padding: 8px 0 24px;
   font: var(--sans10);
   letter-spacing: .2em;
   text-transform: uppercase;
   margin-bottom: 4px;
}

#navstrip a {
   color: hsl(var(--gray2));
}

#navstrip a:first-of-type {
   font-weight: 700;
   color: hsl(var(--accent1-med));
}

a.mobile-jump-bottom,
a.mobile-jump-top {
   display: none;
}


@media only screen and (max-width: 800px) {
   a.mobile-jump-bottom {
      position: fixed;
      z-index: 50;
      bottom: 60px;
      right: 24px;
      width: 40px;
      height: 40px;
      background: hsl(var(--darkgray));
      border: 1px solid var(--bordercolor);
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 20px;
      color: hsl(var(--gray3));
   }

   a.mobile-jump-top {
      position: fixed;
      z-index: 50;
      bottom: 110px;
      right: 24px;
      width: 40px;
      height: 40px;
      background: hsl(var(--darkgray));
      border: 1px solid var(--bordercolor);
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 20px;
      color: hsl(var(--gray3));
   }

}


/***********************************
 HOME FUNDAMENTALS
************************************/

.flexrow {
   display: flex;
}

.flexcol {
   display: flex;
   flex-direction: column;
}

.button a:hover {
   opacity: 1;
}

.button a::before {
   content: '';
   position: absolute;
   top: 0;
   left: 0;
   width: 0%;
   height: 100%;
   border-top: 0px solid hsl(var(--accent2-med) / .2);
   border-bottom: 2px solid hsl(var(--accent2-med) / .2);
   transition: .25s;
}

.button a:hover::before {
   width: 100%;
}

.tooltip {
   position: relative;
   display: inline-block;
   /* If you want dots under the hoverable text */
}

/* Tooltip text */
.tooltip .tooltiptext {
   visibility: hidden;
   width: 120px;
   background-color: red;
   color: #fff;
   text-align: center;
   padding: 5px 0;
   border-radius: 6px;

   /* Position the tooltip text - see examples below! */
   position: absolute;
   z-index: 1;
}

/* Show the tooltip text when you mouse over the tooltip container */
.tooltip:hover .tooltiptext {
   visibility: visible;
}






