      flex-grow: 4;
   }

   .stafftemp h1,
   [class*="temp"] h1 {
      font: italic var(--serif36);
   }

   .posttemp1,
   .posttemp2,
   .posttemp3 {
      padding: 32px 24px;
   }

   .post4-body {
      padding: 24px 32px calc(24px + var(--insetgap));
   }

   .post4-header {
      height: 60px;
   }

   .post5-header {
      height: 82px;
   }

   .post5-banner {
      height: 100px;
      margin-bottom: 24px;
   }

   .post5-body {
      padding: calc(16px + var(--insetgap)) 24px 32px;
   }

   .posttemp6 {
      grid-template:
         'inner' auto
         'gap2' 64px
         / 1fr;
   }

   .post6-inner {
      border: 0;
      border-bottom: 1px solid var(--bordercolor);
   }

   .post6-header {
      padding: 20px 24px;
   }

   .post6-banner {
      height: 100px;
   }

   .post6-body {
      padding: 24px 24px 28px;
   }

   .posttemp6 .flavortext,
   .posttemp8 .flavortext {
      writing-mode: unset;
      text-orientation: mixed;
      white-space: unset;
      right: 0;
      bottom: -64px;
      width: 100%;
      min-width: 0;
      height: 64px;
      padding: 0 24px;
      justify-content: flex-end;
   }

   .posttemp6 .flavortext::before,
   .posttemp8 .flavortext::before {
      display: none;
   }

   .posttemp7 {
      grid-template-columns: 1fr;
   }

   .post7-header {
      width: 100%;
      padding: 24px;
   }

   .post7-icon {
      width: 60px;
      height: 60px;
   }

   .post7-body {
      width: 100%;
      padding: 24px 24px 32px;
   }

   .posttemp7 .flavortext {
      display: none;
   }

   .posttemp8 {
      grid-template:
         'body'
         'sidebar';
   }

   .post8-body {
      padding: 24px;
   }

   .post8-sidebar {
      height: 64px;
      padding: 0 24px;
      border-left: 0;
      border-top: 1px solid var(--bordercolor)
   }


   .imggrid {
      gap: 12px;
   }

}


















